import React, { useState } from 'react';
import api from '../../services/api';
import FlightCard from './FlightCard';

const MAX_PRICE = 2000;

const FlightSearch = () => {
  const [filters, setFilters] = useState({
    departure_city: '',
    destination_city: '',
    flight_date: '',
  });
  const [priceRange, setPriceRange] = useState([0, MAX_PRICE]);
  const [results, setResults] = useState([]);
  const [searched, setSearched] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFilters((prev) => ({ ...prev, [name]: value }));
  };

  const handleMinSlider = (e) => {
    const val = Math.min(Number(e.target.value), priceRange[1] - 10);
    setPriceRange([val, priceRange[1]]);
  };

  const handleMaxSlider = (e) => {
    const val = Math.max(Number(e.target.value), priceRange[0] + 10);
    setPriceRange([priceRange[0], val]);
  };

  const minPercent = (priceRange[0] / MAX_PRICE) * 100;
  const maxPercent = (priceRange[1] / MAX_PRICE) * 100;

  const handleSearch = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    setSearched(true);

    const params = Object.fromEntries(
      Object.entries(filters).filter(([, v]) => v !== '')
    );

    if (priceRange[0] > 0) params.min_price = priceRange[0];
    if (priceRange[1] < MAX_PRICE) params.max_price = priceRange[1];

    try {
      const res = await api.get('/flights/search', { params });
      setResults(res.data.data || []);
    } catch (err) {
      setError('Search failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setFilters({ departure_city: '', destination_city: '', flight_date: '' });
    setPriceRange([0, MAX_PRICE]);
    setResults([]);
    setSearched(false);
    setError('');
  };

  return (
    <div className="page-container">
      <div className="page-header">
        <h1>Search Flights</h1>
        <p>Find your perfect flight</p>
      </div>

      <div className="card search-card">
        <form onSubmit={handleSearch}>
          <div className="form-row">
            <div className="form-group">
              <label>From (City)</label>
              <input
                type="text"
                name="departure_city"
                value={filters.departure_city}
                onChange={handleChange}
                placeholder="e.g. Karachi"
              />
            </div>
            <div className="form-group">
              <label>To (City)</label>
              <input
                type="text"
                name="destination_city"
                value={filters.destination_city}
                onChange={handleChange}
                placeholder="e.g. Lahore"
              />
            </div>
            <div className="form-group">
              <label>Date</label>
              <input
                type="date"
                name="flight_date"
                value={filters.flight_date}
                onChange={handleChange}
              />
            </div>
          </div>

          <div className="price-range-group">
            <div className="price-range-header">
              <label>Price Range</label>
              <span className="price-range-values">
                ${priceRange[0].toLocaleString()} — ${priceRange[1].toLocaleString()}
              </span>
            </div>
            <div className="slider-track-wrapper">
              <div className="slider-track">
                <div
                  className="slider-fill"
                  style={{ left: `${minPercent}%`, width: `${maxPercent - minPercent}%` }}
                />
              </div>
              <input
                type="range"
                min={0}
                max={MAX_PRICE}
                step={10}
                value={priceRange[0]}
                onChange={handleMinSlider}
                className="range-input range-min"
              />
              <input
                type="range"
                min={0}
                max={MAX_PRICE}
                step={10}
                value={priceRange[1]}
                onChange={handleMaxSlider}
                className="range-input range-max"
              />
            </div>
            <div className="price-range-labels">
              <span>$0</span>
              <span>$2,000</span>
            </div>
          </div>

          <div className="form-actions">
            <button type="submit" className="btn-primary" disabled={loading}>
              {loading ? 'Searching...' : '🔍 Search Flights'}
            </button>
            <button type="button" className="btn-secondary" onClick={handleReset}>
              Reset
            </button>
          </div>
        </form>
      </div>

      {error && <div className="alert alert-error">{error}</div>}

      {searched && !loading && (
        <div className="search-results">
          <h2>{results.length} Flight{results.length !== 1 ? 's' : ''} Found</h2>
          {results.length === 0 ? (
            <div className="empty-state">No flights match your search criteria.</div>
          ) : (
            <div className="flights-grid">
              {results.map((flight) => (
                <FlightCard key={flight.flight_id} flight={flight} isAdmin={false} />
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default FlightSearch;
